sql:
SELECT customer_id
FROM campaign_responses
WHERE accepted_cmp3 = 0 AND accepted_cmp4 = 0;

SELECT customer_id, SUM(z_revenue) AS total_revenue
FROM cost_revenue
GROUP BY customer_id;

SELECT customer_id
FROM purchases
WHERE mnt_wines > 1000 AND num_web_purchases > 3;

SELECT DISTINCT customer_id, accepted_cmp3
FROM campaign_responses
WHERE accepted_cmp3 = 1;

SELECT DISTINCT customer_id
FROM complaints
WHERE complain = 1;

external_knowledge:
- 'Explorers' metaphorically refers to customers who engage in purchases;
- 'Golden lands of marketing allure' symbolizes the marketing campaigns that attract customer attention;
- 'Journey through the marketplace' represents the details of their shopping, including categories of spending and revenue;
- 'Enchanted by the call of a campaign's siren song' refers to customers responding positively (response = 1) to the marketing campaigns.

sql:
SELECT customer_id
FROM campaign_responses
WHERE accepted_cmp1 = 0 AND accepted_cmp2 = 0 AND accepted_cmp3 = 0 AND accepted_cmp4 = 0 AND accepted_cmp5 = 0;

SELECT purchases.purchase_id, purchases.customer_id, campaign_responses.accepted_cmp3
FROM purchases
INNER JOIN campaign_responses ON purchases.customer_id = campaign_responses.customer_id;

SELECT SUM(crv.total_lifetime_value) AS total_nourished_value
FROM cost_revenue crv
INNER JOIN complaints c ON crv.customer_id = c.customer_id;

SELECT customer_id, total_lifetime_value
FROM cost_revenue
WHERE customer_acquisition_cost > 5.0;

SELECT p.customer_id, p.total_revenue
FROM purchases p
INNER JOIN cost_revenue cr ON p.customer_id = cr.customer_id;

SELECT accepted_cmp1, accepted_cmp2, accepted_cmp3, accepted_cmp4, accepted_cmp5
FROM campaign_responses
WHERE customer_id = (
  SELECT customer_id
  FROM cost_revenue
  WHERE total_lifetime_value = (
    SELECT MAX(total_lifetime_value)
    FROM cost_revenue
  )
);
